service-task-definition.script:
const SERVICE = 'bedrock';

const main = () => {
    ////// == 工程コンフィグ・ワークフローデータの参照 / Config & Data Retrieving ==
    const awsKey = configs.getObject('conf_AccessKey').getToken();
    const awsSecret = configs.getObject('conf_SecretKey').getToken();
    const region = retrieveRegion();
    let model = retrieveModel();
    const useCrossRegion = configs.getObject("conf_UseCrossRegion");
    if (useCrossRegion) {
        model = decideCrossRegionModel(model, region);
    }

    const maxTokens = retrieveMaxTokens();
    const temperature = retrieveTemperature();
    const systemPrompt = configs.get('conf_SystemPrompt');
    const userMessage = retrieveUserMessage(); // 添付画像の取得も含む

    ////// == 演算 / Calculating ==
    const answer = converse(
        awsKey,
        awsSecret,
        region,
        model,
        maxTokens,
        temperature,
        systemPrompt,
        userMessage
    );

    ////// == ワークフローデータへの代入 / Data Updating ==
    saveData('conf_Answer1', answer);
}

/**
 * config からリージョンコードを読み出す
 * リージョンコードの形式として不正な場合はエラー
 * @return {String}
 */
const retrieveRegion = () => {
    const region = configs.get('conf_Region');
    // 今後リージョンが増えることも考えて、中央の最大文字数には余裕をみている
    const reg = new RegExp('^[a-z]{2}-[a-z]{4,16}-[1-9]$');
    if (!reg.test(region)) {
        throw new Error('Region Code is invalid.');
    }
    return region;
}

/**
 * config からモデル ID を読み出す
 * モデル ID として不正な場合はエラー
 * @return {String}
 */
const retrieveModel = () => {
    const model = configs.get('conf_Model');
    const reg = new RegExp('^[a-z0-9.:-]+$');
    if (!reg.test(model)) {
        throw new Error('Model is invalid. It contains an invalid character.');
    }
    const MODEL_PREFIX = 'mistral.';
    if (!model.startsWith(MODEL_PREFIX)){
        throw new Error(`Model is invalid. It must start with "${MODEL_PREFIX}".`);
    }
    return model;
}

/**
 * クロスリージョン推論モデル ID を決定する
 * @return {String}
 */
const decideCrossRegionModel = (model, region) => {
    if (region.startsWith('us-')) {
        return `us.${model}`;
    } else if(region.startsWith('eu-')) {
        return `eu.${model}`;
    }
    throw new Error(`Cross-region inference is not supported in ${region}.`);
}

/**
 * config から最大トークン数を読み出す
 * 正の整数でない場合、エラー
 * 未定義の場合、null を返す
 * @returns {Number}
 */
const retrieveMaxTokens = () => {
    const maxTokens = configs.get('conf_MaxTokens');
    if (maxTokens === '') {
        return null;
    }
    const regExp = new RegExp(/^[1-9][0-9]*$/);
    if (!regExp.test(maxTokens)) {
        throw new Error('Maximum number of tokens for generating output must be a positive integer.');
    }
    return parseInt(maxTokens, 10);
};

/**
 * config から温度を読み出す
 * 未定義の場合、null を返す
 * @returns {Number}
 */
const retrieveTemperature = () => {
    const temperature = configs.get('conf_Temperature');
    if (temperature === '') {
        return null;
    }
    const regExp = /^(0(\.\d+)?|1(\.0+)?)$/;
    if (!regExp.test(temperature)) {
        throw new Error('Temperature must be a number from 0 to 1.');
    }
    return parseFloat(temperature);
};

// https://docs.mistral.ai/studio-api/conversations/vision#faq
const MAX_IMAGE_NUM = 8; // Mistral AI の制限。1 リクエストにつき添付画像 8 個まで
const MAX_IMAGE_SIZE = 10000000; // Mistral AI の制限。1 ファイルにつき 10 Mb まで
const ALLOWED_MEDIA_TYPES = ['image/jpeg', 'image/png', 'image/gif', 'image/webp'];

/**
 * config からユーザメッセージ（添付画像を含む）を読み出す
 * ユーザメッセージが空の場合、添付画像が不正な場合はエラー
 * @returns {Object} ユーザメッセージオブジェクト
 */
const retrieveUserMessage = () => {
    const message = configs.get('conf_Message1');
    if (message === '') {
        throw new Error('User Message is empty.');
    }
    const imageFiles = retrieveImageFiles();
    validateFiles(imageFiles, 'image', MAX_IMAGE_NUM, MAX_IMAGE_SIZE);
    const inlineImages = imageFiles.map(file => ({
        image: fileToObj(file)
    }));
    const userMessage = {
        role: 'user',
        content: [
            {
                text: message
            },
            ...inlineImages
        ]
    };
    return userMessage;

};

/**
 * config から画像ファイルを読み出す
 * 以下の場合はエラー
 * - Content-Type が許可されていない場合
 * @returns {Array<Qfile>} ファイルオブジェクトの配列
 */
const retrieveImageFiles = () => {
    const imageFiles = [];

    const filesDef = configs.getObject('conf_Images1');
    if (filesDef === null) {
        return imageFiles;
    }
    const files = engine.findData(filesDef);
    if (files === null) {
        return imageFiles;
    }
    files.forEach(file => {
        const contentType = file.getContentType().split(';')[0];
        if (ALLOWED_MEDIA_TYPES.includes(contentType)){
            imageFiles.push(file);
        } else {
            throw new Error(`Content-Type of the attached file "${file.getName()}" is not allowed.`);
        }
    });
    return imageFiles;
};

/**
 * ファイルの総数、サイズをチェックする
 * 以下の場合はエラー
 * - 添付ファイルの総数が多すぎる場合
 * - ファイルサイズが大きすぎる場合
 * @param {Array<Qfile>} ファイルオブジェクトの配列
 * @param errorLabel
 * @param maxNum
 * @param maxSize
 */
const validateFiles = (files, errorLabel, maxNum, maxSize) => {
    if (files.length > maxNum) {
        throw new Error(`Too many ${errorLabel}s attached. The maximum number is ${maxNum}.`);
    }
    files.forEach(file => {
        if (file.getLength() > maxSize) {
            throw new Error(`Attached ${errorLabel} file "${file.getName()}" is too large. The maximum size is ${maxSize} bytes.`);
        }
    });
}

/**
 * ファイルから inline コンテンツに必要な source, format を読み出し、ファイルオブジェクトを返す
 * @param {Qfile} file  ファイルオブジェクト
 */
const fileToObj = file => ({
    format : file.getContentType().split(';')[0].split('/')[1],
    source: {
        bytes: base64.encodeToString(fileRepository.readFile(file))
    }
});


/**
 * モデルの実行
 * @param awsKey
 * @param awsSecret
 * @param region
 * @param model
 * @param maxTokens
 * @param temperature
 * @param systemPrompt
 * @param userMessage
 * @returns {String} answer
 */
const converse = (
    awsKey,
    awsSecret,
    region,
    model,
    maxTokens,
    temperature,
    systemPrompt,
    userMessage
) => {
    const URL = `https://bedrock-runtime.${region}.amazonaws.com/model/${model}/converse`;
    const inferenceConfig = {};
    if (maxTokens !== null) {
        inferenceConfig.maxTokens = maxTokens;
    }
    if (temperature !== null) {
        inferenceConfig.temperature = temperature;
    }
    const payload = {
        inferenceConfig,
        messages: [userMessage]
    };

    if (systemPrompt !== '') {
        Object.assign(payload, {
            system: [
                {text :`${systemPrompt}`}
            ]
        });
    }

    const response = httpClient.begin()
        .awsSignV4(awsKey, awsSecret, region, SERVICE)
        .body(JSON.stringify(payload), 'application/json')
        .post(URL);

    const status = response.getStatusCode();
    const respTxt = response.getResponseAsString();
    if (status !== 200) {
        engine.log(respTxt);
        throw new Error(`Failed to converse. status: ${status}`);
    }
    const {output, stopReason, usage} = JSON.parse(respTxt);
    // 推論の要約 reasoningContent を返すモデルは今のところなし
    engine.log(`Stop Reason: ${stopReason}`);
    engine.log(`Input Tokens: ${usage.inputTokens}`);
    engine.log(`Output Tokens: ${usage.outputTokens}`);

    // text プロパティを持つ content をすべて連結して回答とする
    const answer1 = output.message.content
        .filter(content => content.text !== undefined)
        .map(content => content.text)
        .join('');
    if (answer1 === null || answer1.trim() === '') {
        throw new Error(`No response content generated. Stop Reason: ${stopReason}`);
    }
    return answer1;
};

/**
 * データ項目への保存
 * @param configName
 * @param data
 */
const saveData = (configName, data) => {
    const def = configs.getObject(configName);
    if (def === null) {
        return;
    }
    engine.setData(def, data);
};

service-task-definition.test:
/**
 * 設定の準備
 * @param key
 * @param secret
 * @param region
 * @param model
 * @param useCrossRegion
 * @param maxTokens
 * @param temperature
 * @param systemPrompt
 * @param message
 * @returns {ProcessDataDefinitionView} answerDef
 */
const prepareConfigs = (key, secret, region, model, useCrossRegion, maxTokens, temperature, systemPrompt, message) => {
    // 認証設定を作成し、指定
    const keyAuth = httpClient.createAuthSettingToken('Access Key', key);
    configs.putObject('conf_AccessKey', keyAuth);
    const secretAuth = httpClient.createAuthSettingToken('Secret Access Key', secret);
    configs.putObject('conf_SecretKey', secretAuth);

    configs.put('conf_Region', region);
    configs.put('conf_Model', model);
    configs.putObject('conf_UseCrossRegion', useCrossRegion);
    configs.put('conf_MaxTokens', maxTokens);
    configs.put('conf_Temperature', temperature);
    configs.put('conf_SystemPrompt', systemPrompt);
    configs.put('conf_Message1', message);

    // 回答を保存するデータ項目を作成し、指定
    const answerDef = engine.createDataDefinition('回答', 1, 'q_response', 'STRING_TEXTAREA');
    configs.putObject('conf_Answer1', answerDef);
    engine.setData(answerDef, '事前文字列');
    return answerDef;
};

/**
 * 異常系のテスト
 * @param errorMsg
 */
const assertError = (errorMsg) => {
    let failed = false;
    try {
        main();
    } catch (e) {
        failed = true;
        expect(e.message).toEqual(errorMsg);
    }
    if (!failed) {
        fail('No error was thrown.');
    }
};

const MODEL_LARGE = 'mistral.mistral-large-3-675b-instruct';
const MODEL_14B = 'mistral.ministral-3-14b-instruct';
const MODEL_8B = 'mistral.ministral-3-8b-instruct';
const MODEL_3B = 'mistral.ministral-3-3b-instruct';
const MODEL_MAGISTRAL = 'mistral.magistral-small-2509';
const MODEL_PIXTRAL = 'mistral.pixtral-large-2502-v1:0';

/**
 * リージョンコードの形式が不正 - ハイフンを含まない
 */
test('Region Code is invalid - no hyphens', () => {
    prepareConfigs('key-12345', 'secret-67890', 'invalidregioncode', MODEL_LARGE, false, '', '', '', 'Hello');
    assertError('Region Code is invalid.');
});

/**
 * リージョンコードの形式が不正 - ハイフンの間の文字列が長すぎる
 */
test('Region Code is invalid - too many characters', () => {
    prepareConfigs('key-12345', 'secret-67890', 'eu-toomanycharacters-1', MODEL_LARGE, false, '', '', '', 'Hello');
    assertError('Region Code is invalid.');
});

/**
 * モデルの指定が不正 - 不正な文字を含む
 */
test('Model is invalid - contains an invalid character', () => {
    prepareConfigs('key-12345', 'secret-67890', 'us-east-1', 'mistral.mistral-テスト', false, '', '', '', 'Hello');
    assertError('Model is invalid. It contains an invalid character.');
});

/**
 * モデルの指定が不正 - mistral. で始まらない
 */
test('Model is invalid - does not start with the prefix', () => {
    prepareConfigs('key-12345', 'secret-67890', 'us-east-1', 'invalid-model-2.0:1', false, '', '', '', 'Hello');
    assertError('Model is invalid. It must start with "mistral.".');
});

/**
 * リージョンコードがクロスリージョン推論の対象でない
 */
test('Region is not supported by cross-region inference', () => {
    prepareConfigs('key-12345', 'secret-67890', 'ap-northeast-1', MODEL_PIXTRAL, true, '', '', '', 'Hello');
    assertError('Cross-region inference is not supported in ap-northeast-1.');
});

/**
 * トークン数の最大値が正の整数でない - 数字でない文字を含む場合
 */
test('Maximum number of tokens must be a positive integer - includes a non-numeric character', () => {
    prepareConfigs('key-12345', 'secret-67890', 'us-east-1', MODEL_LARGE, false, '1.1', '', '', 'Hello');
    assertError('Maximum number of tokens for generating output must be a positive integer.');
});

/**
 * トークン数の最大値が正の整数でない - ゼロ
 */
test('Maximum number of tokens must be a positive integer - 0', () => {
    prepareConfigs('key-12345', 'secret-67890', 'us-east-1', MODEL_LARGE, false, '0', '', '', 'Hello');
    assertError('Maximum number of tokens for generating output must be a positive integer.');
});

/**
 * 温度が不正 - 数字、小数点でない文字を含む
 */
test('Invalid temperature - includes a non-numeric character', () => {
    prepareConfigs('key-12345', 'secret-67890', 'us-east-1', MODEL_LARGE, false, '', '-0.1', '', 'Hello');
    assertError('Temperature must be a number from 0 to 1.');
});

/**
 * 温度が不正 - 1 を超える
 */
test('Invalid temperature - bigger than 1', () => {
    prepareConfigs('key-12345', 'secret-67890', 'us-east-1', MODEL_LARGE, false, '', '1.1', '', 'Hello');
    assertError('Temperature must be a number from 0 to 1.');
});

/**
 * メッセージが空
 */
test('Message is empty', () => {
    prepareConfigs('key-12345', 'secret-67890', 'us-east-1', MODEL_LARGE, false, '', '', '', '');
    assertError('User Message is empty.');
});

/**
 * 指定サイズのファイルを作成
 * @param name
 * @param contentType
 * @param size
 * @return qfile
 */
const createQfile = (name, contentType, size) => {
    let text = '';
    if (size >= 4000) {
      text = 'aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa'.repeat(100); // 40 * 100 = 4000
    }
    while (text.length < size) {
        if (text.length !== 0 && text.length * 2 <= size) {
            text += text;
        } else if (text.length + 1000 <= size) {
            text += 'aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa'.repeat(25); // 40 * 25 = 1000
        } else {
            text += 'a';
        }
    }
    return engine.createQfile(name, contentType, text);
};

/**
 * 画像を添付
 * @param {Array<Qfile>} files
 */
const attachFiles = (files) => {
    const filesDef = engine.createDataDefinition('添付画像', 2, 'q_files', 'FILE');
    engine.setData(filesDef, files);
    configs.putObject('conf_Images1', filesDef);
};

/**
 * 添付画像ファイルの数が多すぎる
 */
test('Too many images attached', () => {
    prepareConfigs('key-12345', 'secret-67890', 'us-east-1', MODEL_PIXTRAL, false, '', '', '', 'Describe the images.');
    const images = [];
    for (let i = 0; i < MAX_IMAGE_NUM + 1; i++) {
        images.push(createQfile(`画像${i}.png`, 'image/png', 100));
    }
    attachFiles(images);
    assertError(`Too many images attached. The maximum number is ${MAX_IMAGE_NUM}.`);
});

/**
 * 添付画像ファイルのサイズが大きすぎる
 */
test('Attached image is too large', () => {
    prepareConfigs('key-12345', 'secret-67890', 'us-east-1', MODEL_PIXTRAL, false, '', '', '', 'Describe the images.');
    const image1 = createQfile('画像1.png', 'image/png', 100);
    const image2 = createQfile('画像2.jpg', 'image/jpeg', MAX_IMAGE_SIZE + 1);
    attachFiles([image1, image2]);
    assertError(`Attached image file "画像2.jpg" is too large. The maximum size is ${MAX_IMAGE_SIZE} bytes.`);
});

/**
 * 添付ファイルに許可されていない Content-Type のファイルを含む
 */
test('Content-Type of an attached file is not allowed', () => {
    prepareConfigs('key-12345', 'secret-67890', 'us-east-1', MODEL_PIXTRAL, false, '', '', '', 'Describe the images.');
    const image1 = createQfile('画像1.png', 'image/png;filename="画像1.png"', 100);
    const image2 = createQfile('画像2.jpg', 'image/jpeg', 200);
    const image3 = createQfile('画像3.gif', 'image/gif', 300);
    const image4 = createQfile('画像4.webp', 'image/webp', 100);
    const notAllowed = createQfile('doc.pdf', 'application/pdf', 200);
    attachFiles([image1, image2, image3, image4, notAllowed]);
    assertError('Content-Type of the attached file "doc.pdf" is not allowed.');
});

/**
 * API リクエストのテスト
 * @param {Object} request
 * @param request.url
 * @param request.method
 * @param request.contentType
 * @param request.body
 * @param {String} region
 * @param {String} model
 * @param {Number} maxTokens
 * @param {Number} temperature
 * @param {String} systemPrompt
 * @param {String} message
 * @param {Array<Qfile>} files
 */
const assertRequest = ({url, method, contentType, body}, region, model, maxTokens, temperature, systemPrompt, message, files = []) => {
    expect(url).toEqual(`https://bedrock-runtime.${region}.amazonaws.com/model/${model}/converse`);
    expect(method).toEqual('POST');
    expect(contentType).toEqual('application/json');
    const bodyObj = JSON.parse(body);

    if (maxTokens !== null) {
        expect(bodyObj.inferenceConfig.maxTokens).toEqual(maxTokens);
    } else {
        expect(bodyObj.inferenceConfig.maxTokens).toEqual(undefined);
    }
    if (temperature !== null) {
        expect(bodyObj.inferenceConfig.temperature).toEqual(temperature);
    } else {
        expect(bodyObj.inferenceConfig.temperature).toEqual(undefined);
    }

    if (systemPrompt !== '') {
        expect(bodyObj.system[0].text).toEqual(systemPrompt);
    } else {
        expect(bodyObj.system).toEqual(undefined);
    }

    expect(bodyObj.messages[0].role).toEqual('user');
    expect(bodyObj.messages[0].content[0].text).toEqual(message);

    expect(bodyObj.messages[0].content.length).toEqual(files.length + 1);
    files.forEach((file, i) => {
        expect(bodyObj.messages[0].content[i + 1].image.format).toEqual(file.getContentType().split(';')[0].split('/')[1]);
        expect(bodyObj.messages[0].content[i + 1].image.source.bytes).toEqual(base64.encodeToString(fileRepository.readFile(file)));
    });
};

/**
 * API のレスポンスボディを作成
 * @param {String} answerText
 * @returns {String} response
 */
const createResponse = (answerText) => {
    const responseObj = {
        stopReason: 'end_turn',
        output: {
            message: {
                content: [
                    {text: answerText}
                ]
            }
        },
        usage: {
            inputTokens: 1024,
            outputTokens: 2048
        }
    };
    return JSON.stringify(responseObj);
};

/**
 * API リクエストでエラー
 * クロスリージョン推論を利用する (us)
 */
test('Fail to request - with cross-region inference', () => {
    const region = 'us-east-1';
    const message = 'Hello';
    prepareConfigs('key-12345', 'secret-67890', region, MODEL_PIXTRAL, true, '1280', '', '', message);

    httpClient.setRequestHandler((request) => {
        assertRequest(request, region, `us.${MODEL_PIXTRAL}`, 1280, null, '', message);
        return httpClient.createHttpResponse(400, 'application/json', '{}');
    });
    assertError('Failed to converse. status: 400');
});

/**
 * レスポンスに回答を含まないため、エラー - text フィールドを持つ content がない場合
 */
test('No response content - no content with text field', () => {
    const region = 'us-east-1';
    const message = 'Hello';
    prepareConfigs('key-12345', 'secret-67890', region, MODEL_LARGE, false, '', '', '', message);

    const responseObj = {
        stopReason: 'max_tokens',
        output: {
            message: {
                content: [
                    {toolUse: {}}
                ]
            }
        },
        usage: {
            inputTokens: 1024,
            outputTokens: 2048
        }
    };
    httpClient.setRequestHandler((request) => {
        assertRequest(request, region, MODEL_LARGE, null, null, '', message);
        return httpClient.createHttpResponse(200, 'application/json', JSON.stringify(responseObj));
    });
    assertError('No response content generated. Stop Reason: max_tokens');
});

/**
 * レスポンスに回答を含まないため、エラー - text フィールドの値が空の場合
 */
test('No response content - content with text field is empty', () => {
    const region = 'us-east-1';
    const message = 'Hello';
    prepareConfigs('key-12345', 'secret-67890', region, MODEL_14B, false, '', '', '', message);

    const responseObj = {
        stopReason: 'max_tokens',
        output: {
            message: {
                content: [
                    {text: ''}
                ]
            }
        },
        usage: {
            inputTokens: 1024,
            outputTokens: 2048
        }
    };
    httpClient.setRequestHandler((request) => {
        assertRequest(request, region, MODEL_14B, null, null, '', message);
        return httpClient.createHttpResponse(200, 'application/json', JSON.stringify(responseObj));
    });
    assertError('No response content generated. Stop Reason: max_tokens');
});

/**
 * 成功 - 必須項目のみ指定
 * maxTokens, temperature は未指定のため inferenceConfig に含まれない
 */
test('Success - only with required configs', () => {
    const region = 'us-east-1';
    const message = 'Hello';
    const answerDef = prepareConfigs('key-12345', 'secret-67890', region, MODEL_LARGE, false, '', '', '', message);

    const answer = 'Hi there!';
    httpClient.setRequestHandler((request) => {
        assertRequest(request, region, MODEL_LARGE, null, null, '', message);
        return httpClient.createHttpResponse(200, 'application/json', createResponse(answer));
    });
    expect(main()).toEqual(undefined);
    expect(engine.findData(answerDef)).toEqual(answer);
});

/**
 * 成功 - 最大トークン数、温度を指定
 */
test('Success - with max tokens and temperature', () => {
    const region = 'us-east-1';
    const message = 'Are you a robot?\n\nHow old are you?';
    const answerDef = prepareConfigs('key-12345', 'secret-67890', region, MODEL_8B, false, '500', '0.5', '', message);

    const answer = "I'm an AI model. I don't have an age.";
    httpClient.setRequestHandler((request) => {
        assertRequest(request, region, MODEL_8B, 500, 0.5, '', message);
        return httpClient.createHttpResponse(200, 'application/json', createResponse(answer));
    });
    expect(main()).toEqual(undefined);
    expect(engine.findData(answerDef)).toEqual(answer);
});

/**
 * 成功 - 温度、システムプロンプトを指定
 * 添付画像のデータ項目は指定しているが、添付ファイルなし
 */
test('Success - with temperature and system prompt, empty attached files', () => {
    const region = 'eu-central-2';
    const systemPrompt = "You are a translator. Translate the user's input into Japanese.";
    const message = 'Hi. How are you?';
    const answerDef = prepareConfigs('key-12345', 'secret-67890', region, MODEL_3B, false, '', '0', systemPrompt, message);
    attachFiles([]);

    const answer = 'こんにちは。お元気ですか？';
    httpClient.setRequestHandler((request) => {
        assertRequest(request, region, MODEL_3B, null, 0, systemPrompt, message);
        return httpClient.createHttpResponse(200, 'application/json', createResponse(answer));
    });
    expect(main()).toEqual(undefined);
    expect(engine.findData(answerDef)).toEqual(answer);
});

