/**
 * 成功 - 添付画像あり
 * 回答を保存するデータ項目に、文字型 Markdown を指定
 */
test('Success - with attached images - Markdown', () => {
    const region = 'us-east-1';
    const message = 'Describe each image attached.';
    prepareConfigs('key-54321', 'secret-99999', region, MODEL_PIXTRAL, false, '', '', '', message);

    // 回答を保存するデータ項目に、文字型 Markdown を指定
    const answerDef = engine.createDataDefinition('回答', 1, 'q_answer', 'STRING_MARKDOWN');
    engine.setData(answerDef, '事前文字列');
    configs.putObject('conf_Answer1', answerDef);

    // 添付画像を指定
    const files = [];
    files.push(createQfile('画像0.png', 'image/png', 100));
    files.push(createQfile('画像1.jpg', 'image/jpeg', 200));
    files.push(createQfile('画像2.gif', 'image/gif', 300));
    files.push(createQfile('画像3.webp', 'image/webp', 100));
    files.push(createQfile('最大サイズの画像.jpg', 'image/jpeg;filename="最大サイズの画像.jpg"', MAX_IMAGE_SIZE));
    attachFiles(files);

    const answer = 'The 1st image shows a cat. The 2nd image shows a dog.';
    httpClient.setRequestHandler((request) => {
        assertRequest(request, region, MODEL_PIXTRAL, null, null, '', message, files);
        return httpClient.createHttpResponse(200, 'application/json', createResponse(answer));
    });
    expect(main()).toEqual(undefined);
    expect(engine.findData(answerDef)).toEqual(answer);
});

